// ── ANIMATION VARIANTS ────────────────────────────────────────────────────────

const fadeUp = { hidden:{opacity:0,y:40}, show:{opacity:1,y:0,transition:{duration:0.7,ease:[0.25,0.46,0.45,0.94]}} };
const stagger = { show:{ transition:{ staggerChildren:0.1 } } };
const scaleIn = { hidden:{opacity:0,scale:0.9}, show:{opacity:1,scale:1,transition:{duration:0.6,ease:"easeOut"}} };

// ── COMPONENTS ────────────────────────────────────────────────────────────────

function SectionLabel({ children }) {
  return (
    <div className="flex items-center gap-3 mb-3">
      <div className="w-6 h-px bg-cyan-400" />
      <span style={{fontFamily:"'JetBrains Mono',monospace",fontSize:"0.7rem",letterSpacing:"0.15em",textTransform:"uppercase",color:"#22d3ee"}}>
        {children}
      </span>
    </div>
  );
}

function AnimatedSection({ children, className="" }) {
  const ref = useRef(null);
  const inView = useInView(ref, { once:true, margin:"-80px" });
  return (
    <motion.div ref={ref} initial="hidden" animate={inView?"show":"hidden"} variants={stagger} className={className}>
      {children}
    </motion.div>
  );
}

