// ── NAV ───────────────────────────────────────────────────────────────────────

function Nav() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(()=>{
    const handler = ()=>setScrolled(window.scrollY>50);
    window.addEventListener("scroll",handler);
    return ()=>window.removeEventListener("scroll",handler);
  },[]);

  const links = ["about","skills","projects","design","services","contact"];

  return (
    <>
      <motion.nav initial={{y:-80}} animate={{y:0}} transition={{duration:0.6,ease:"easeOut"}} style={{position:"fixed",top:0,left:0,right:0,zIndex:100,padding:"0 5%",height:"70px",display:"flex",alignItems:"center",justifyContent:"space-between",background:scrolled?"rgba(5,10,18,0.95)":"rgba(5,10,18,0.7)",backdropFilter:"blur(20px)",borderBottom:`1px solid ${scrolled?"rgba(34,211,238,0.15)":"rgba(34,211,238,0.06)"}`,transition:"all 0.3s"}}>
        <a href="#hero" style={{fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:"1.1rem",color:"#fff",textDecoration:"none",letterSpacing:"-0.02em"}}>
          JAA<span style={{color:"#22d3ee"}}>.</span>
        </a>
        <div className="nav-links-desktop" style={{display:"flex",gap:"2rem",listStyle:"none",alignItems:"center"}}>
          {links.map(l=>(
            <a key={l} href={`#${l}`} style={{fontFamily:"'JetBrains Mono',monospace",fontSize:"0.72rem",color:"#64748b",textDecoration:"none",letterSpacing:"0.08em",textTransform:"uppercase",transition:"color 0.2s",padding:l==="contact"?"0.45rem 1.1rem":"0",border:l==="contact"?"1px solid rgba(34,211,238,0.3)":"none",borderRadius:l==="contact"?"4px":"0",background:l==="contact"?"transparent":"transparent"}}
              onMouseEnter={e=>e.target.style.color="#22d3ee"} onMouseLeave={e=>e.target.style.color="#64748b"}>
              {l}
            </a>
          ))}
        </div>
        <button className="hamburger-btn" onClick={()=>setMobileOpen(!mobileOpen)} style={{display:"none",flexDirection:"column",gap:"5px",background:"none",border:"none",cursor:"pointer",padding:"4px"}}>
          {[0,1,2].map(i=><span key={i} style={{display:"block",width:"22px",height:"2px",background:"#94a3b8",transition:"all 0.3s"}} />)}
        </button>
      </motion.nav>

      <AnimatePresence>
        {mobileOpen && (
          <motion.div initial={{opacity:0,y:-20}} animate={{opacity:1,y:0}} exit={{opacity:0,y:-20}} style={{position:"fixed",top:"70px",left:0,right:0,background:"rgba(5,10,18,0.98)",backdropFilter:"blur(20px)",borderBottom:"1px solid rgba(34,211,238,0.1)",padding:"1.5rem 5%",zIndex:99,display:"flex",flexDirection:"column",gap:"1.2rem"}}>
            {links.map(l=>(
              <a key={l} href={`#${l}`} onClick={()=>setMobileOpen(false)} style={{fontFamily:"'JetBrains Mono',monospace",fontSize:"0.82rem",color:"#64748b",textDecoration:"none",letterSpacing:"0.08em",textTransform:"uppercase",transition:"color 0.2s"}}
                onMouseEnter={e=>e.target.style.color="#22d3ee"} onMouseLeave={e=>e.target.style.color="#64748b"}>
                {l}
              </a>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

